const env = {
    CUSTOM_FILE_NAME: process.env.CUSTOM_FILE_NAME,
    MEMBERS: process.env.MEMBERS,
    LABELS: process.env.LABELS,
    LISTS_RANGE: process.env.LISTS_RANGE,
};

window.TrelloPowerUp.initialize({
    'board-buttons': function () {
        return [{
            icon: 'https://cdn.glitch.com/1b42d7fe-bda8-4af8-a6c8-eff0cea9e08a%2Frocket-ship.png?1494946700421',
            text: 'Pivot Table',
            callback: function (t) {
                return t.board('all').then(async function (board) {
                    const members = board.members.filter(member => env.MEMBERS.includes(member.username));
                    const labels = board.labels.filter(label => label.name.trim() !== '' && env.LABELS.includes(label.name));
                    const lists = await t.lists('all');
                    const listsRange = env.LISTS_RANGE.split(',');
                    const listsNames = lists.map(list => list.name);
                    const firstListIndex = listsNames.indexOf(listsRange[0]);
                    const lastListIndex = listsNames.indexOf(listsRange[1]);
                    const neededLists = lists.splice(firstListIndex, lastListIndex);
                    const neededListsIds = neededLists.map(list => list.id);
                    console.log(neededLists);
                    const cards = await t.cards('all');
                    const neededCards = cards.filter(card => card.idList in neededListsIds);
                    console.log(neededCards);
                });
            }
        }];
    },
});
